import Link from 'next/link';
import styles from './Footer.module.css';
import { X, Instagram, Facebook } from 'lucide-react';

const Footer = () => {
    return (
        <footer className={styles.footer}>
            <div className={`${styles.container} container`}>
                <div className={styles.top}>
                    <div className={styles.brand}>
                        <h2 className={styles.logo}>First</h2>
                        <p>تابعنا عبر</p>
                        <div className={styles.socials}>
                            <Link href="#"><X size={20} /></Link>
                            <Link href="#"><Instagram size={20} /></Link>
                            <Link href="#"><Facebook size={20} /></Link>
                        </div>
                    </div>

                    <div className={styles.links}>
                        <div className={styles.column}>
                            <h3>روابط سريعة</h3>
                            <ul>
                                <li><Link href="/">الرئيسية</Link></li>
                                <li><Link href="/features">المميزات</Link></li>
                                <li><Link href="/packages">الباقات</Link></li>
                            </ul>
                        </div>

                        <div className={styles.column}>
                            <h3>الشروط والاحكام</h3>
                            <ul>
                                <li><Link href="/terms">سياسة الدفع</Link></li>
                                <li><Link href="/privacy">سياسة الخصوصية</Link></li>
                                <li><Link href="/refund">سياسة الاسترداد</Link></li>
                            </ul>
                        </div>

                        <div className={styles.column}>
                            <h3>للأكاديميات</h3>
                            <ul>
                                <li><Link href="/register">سجل أكاديميتك</Link></li>
                                <li><Link href="/login">تسجيل الدخول</Link></li>
                                <li><Link href="/support">الدعم الفني</Link></li>
                            </ul>
                        </div>
                    </div>
                </div>
            </div>
        </footer>
    );
};

export default Footer;